SELECT transaction_id, COUNT(search_id) AS search_count 
FROM transaction_search 
GROUP BY transaction_id;

SELECT ut.transaction_role, COUNT(ut.user_transaction_id) AS total_role_transactions
FROM user_transactions ut
GROUP BY ut.transaction_role;

SELECT event_type, COUNT(event_id) AS "Total_Events"
FROM system_events
GROUP BY event_type;
